 182 | impl BedrockProvider {
 183 |     /// Create from a bearer token (API Gateway / Vault key).
 184 |     #[allow(dead_code)]
 185 |     pub fn new(api_key: String) -> Result<Self> {
 186 |         Self::with_region(api_key, DEFAULT_REGION.to_string())
 187 |     }
 188 | 
 189 |     /// Create from a bearer token with a specific region.
 190 |     pub fn with_region(api_key: String, region: String) -> Result<Self> {
 191 |         tracing::debug!(
 192 |             provider = "bedrock",
 193 |             region = %region,
 194 |             auth = "bearer_token",
 195 |             "Creating Bedrock provider"
 196 |         );
 197 |         Ok(Self {
 198 |             client: Client::new(),
 199 |             auth: BedrockAuth::BearerToken(api_key),
 200 |             region,
 201 |         })
 202 |     }
 203 | 
 204 |     /// Create from AWS IAM credentials (SigV4 signing).
 205 |     pub fn with_credentials(credentials: AwsCredentials, region: String) -> Result<Self> {
 206 |         tracing::debug!(
 207 |             provider = "bedrock",
 208 |             region = %region,
 209 |             auth = "sigv4",
 210 |             "Creating Bedrock provider with AWS credentials"
 211 |         );
 212 |         Ok(Self {
 213 |             client: Client::new(),
 214 |             auth: BedrockAuth::SigV4(credentials),
 215 |             region,
 216 |         })
 217 |     }
