 528 |     /// Dynamically discover available models from the Bedrock API.
 529 |     /// Merges foundation models with cross-region inference profiles.
 530 |     async fn discover_models(&self) -> Result<Vec<ModelInfo>> {
 531 |         let mut models: HashMap<String, ModelInfo> = HashMap::new();
 532 | 
 533 |         // 1) Fetch foundation models
 534 |         let fm_url = format!("{}/foundation-models", self.management_url());
 535 |         let fm_resp = self.send_request("GET", &fm_url, None, "bedrock").await;
 536 | 
 537 |         if let Ok(resp) = fm_resp
 538 |             && resp.status().is_success()
 539 |             && let Ok(data) = resp.json::<Value>().await
 540 |             && let Some(summaries) = data.get("modelSummaries").and_then(|v| v.as_array())
 541 |         {
 542 |             for m in summaries {
 543 |                 let model_id = m.get("modelId").and_then(|v| v.as_str()).unwrap_or("");
 544 |                 let model_name = m.get("modelName").and_then(|v| v.as_str()).unwrap_or("");
 545 |                 let provider_name = m.get("providerName").and_then(|v| v.as_str()).unwrap_or("");
 546 | 
 547 |                 let output_modalities: Vec<&str> = m
 548 |                     .get("outputModalities")
 549 |                     .and_then(|v| v.as_array())
 550 |                     .map(|a| a.iter().filter_map(|v| v.as_str()).collect::<Vec<_>>())
 551 |                     .unwrap_or_default();
 552 | 
 553 |                 let input_modalities: Vec<&str> = m
 554 |                     .get("inputModalities")
 555 |                     .and_then(|v| v.as_array())
 556 |                     .map(|a| a.iter().filter_map(|v| v.as_str()).collect::<Vec<_>>())
 557 |                     .unwrap_or_default();
 558 | 
 559 |                 let inference_types: Vec<&str> = m
 560 |                     .get("inferenceTypesSupported")
 561 |                     .and_then(|v| v.as_array())
 562 |                     .map(|a| a.iter().filter_map(|v| v.as_str()).collect::<Vec<_>>())
 563 |                     .unwrap_or_default();
 564 | 
 565 |                 // Only include TEXT output models with ON_DEMAND or INFERENCE_PROFILE inference
 566 |                 if !output_modalities.contains(&"TEXT")
 567 |                     || (!inference_types.contains(&"ON_DEMAND")
 568 |                         && !inference_types.contains(&"INFERENCE_PROFILE"))
 569 |                 {
 570 |                     continue;
 571 |                 }
 572 | 
 573 |                 // Skip non-chat models
 574 |                 let name_lower = model_name.to_lowercase();
 575 |                 if name_lower.contains("rerank")
 576 |                     || name_lower.contains("embed")
 577 |                     || name_lower.contains("safeguard")
 578 |                     || name_lower.contains("sonic")
 579 |                     || name_lower.contains("pegasus")
 580 |                 {
 581 |                     continue;
 582 |                 }
 583 | 
 584 |                 let streaming = m
 585 |                     .get("responseStreamingSupported")
 586 |                     .and_then(|v| v.as_bool())
 587 |                     .unwrap_or(false);
 588 |                 let vision = input_modalities.contains(&"IMAGE");
 589 | 
 590 |                 // Models with INFERENCE_PROFILE support use cross-region
 591 |                 // us. prefix; ON_DEMAND-only models use bare model IDs.
 592 |                 // Amazon models never get the prefix.
 593 |                 let actual_id = if model_id.starts_with("amazon.") {
 594 |                     model_id.to_string()
 595 |                 } else if inference_types.contains(&"INFERENCE_PROFILE") {
 596 |                     format!("us.{}", model_id)
 597 |                 } else {
 598 |                     model_id.to_string()
 599 |                 };
 600 | 
 601 |                 let display_name = format!("{} (Bedrock)", model_name);
 602 | 
 603 |                 models.insert(
 604 |                     actual_id.clone(),
 605 |                     ModelInfo {
 606 |                         id: actual_id,
 607 |                         name: display_name,
 608 |                         provider: "bedrock".to_string(),
 609 |                         context_window: Self::estimate_context_window(model_id, provider_name),
 610 |                         max_output_tokens: Some(Self::estimate_max_output(model_id, provider_name)),
 611 |                         supports_vision: vision,
 612 |                         supports_tools: true,
 613 |                         supports_streaming: streaming,
 614 |                         input_cost_per_million: None,
 615 |                         output_cost_per_million: None,
 616 |                     },
 617 |                 );
 618 |             }
 619 |         }
 620 | 
 621 |         // 2) Fetch cross-region inference profiles (adds models like Claude Sonnet 4,
 622 |         //    Llama 3.1/3.2/3.3/4, DeepSeek R1, etc. that aren't in foundation models)
 623 |         let ip_url = format!(
 624 |             "{}/inference-profiles?typeEquals=SYSTEM_DEFINED&maxResults=200",
 625 |             self.management_url()
 626 |         );
 627 |         let ip_resp = self.send_request("GET", &ip_url, None, "bedrock").await;
 628 | 
 629 |         if let Ok(resp) = ip_resp
 630 |             && resp.status().is_success()
 631 |             && let Ok(data) = resp.json::<Value>().await
 632 |             && let Some(profiles) = data
 633 |                 .get("inferenceProfileSummaries")
 634 |                 .and_then(|v| v.as_array())
 635 |         {
 636 |             for p in profiles {
 637 |                 let pid = p
 638 |                     .get("inferenceProfileId")
 639 |                     .and_then(|v| v.as_str())
 640 |                     .unwrap_or("");
 641 |                 let pname = p
 642 |                     .get("inferenceProfileName")
 643 |                     .and_then(|v| v.as_str())
 644 |                     .unwrap_or("");
 645 | 
 646 |                 // Only US cross-region profiles
 647 |                 if !pid.starts_with("us.") {
 648 |                     continue;
 649 |                 }
 650 | 
 651 |                 // Skip already-discovered models
 652 |                 if models.contains_key(pid) {
 653 |                     continue;
 654 |                 }
 655 | 
 656 |                 // Skip non-text models
 657 |                 let name_lower = pname.to_lowercase();
 658 |                 if name_lower.contains("image")
 659 |                     || name_lower.contains("stable ")
 660 |                     || name_lower.contains("upscale")
 661 |                     || name_lower.contains("embed")
 662 |                     || name_lower.contains("marengo")
 663 |                     || name_lower.contains("outpaint")
 664 |                     || name_lower.contains("inpaint")
 665 |                     || name_lower.contains("erase")
 666 |                     || name_lower.contains("recolor")
 667 |                     || name_lower.contains("replace")
 668 |                     || name_lower.contains("style ")
 669 |                     || name_lower.contains("background")
 670 |                     || name_lower.contains("sketch")
 671 |                     || name_lower.contains("control")
 672 |                     || name_lower.contains("transfer")
 673 |                     || name_lower.contains("sonic")
 674 |                     || name_lower.contains("pegasus")
 675 |                     || name_lower.contains("rerank")
 676 |                 {
 677 |                     continue;
 678 |                 }
 679 | 
 680 |                 // Guess vision from known model families
 681 |                 let vision = pid.contains("llama3-2-11b")
 682 |                     || pid.contains("llama3-2-90b")
 683 |                     || pid.contains("pixtral")
 684 |                     || pid.contains("claude-3")
 685 |                     || pid.contains("claude-sonnet-4")
 686 |                     || pid.contains("claude-opus-4")
 687 |                     || pid.contains("claude-haiku-4");
 688 | 
 689 |                 let display_name = pname.replace("US ", "");
 690 |                 let display_name = format!("{} (Bedrock)", display_name.trim());
 691 | 
 692 |                 // Extract provider hint from model ID
 693 |                 let provider_hint = pid
 694 |                     .strip_prefix("us.")
 695 |                     .unwrap_or(pid)
 696 |                     .split('.')
 697 |                     .next()
 698 |                     .unwrap_or("");
 699 | 
 700 |                 models.insert(
 701 |                     pid.to_string(),
 702 |                     ModelInfo {
 703 |                         id: pid.to_string(),
 704 |                         name: display_name,
 705 |                         provider: "bedrock".to_string(),
 706 |                         context_window: Self::estimate_context_window(pid, provider_hint),
 707 |                         max_output_tokens: Some(Self::estimate_max_output(pid, provider_hint)),
 708 |                         supports_vision: vision,
 709 |                         supports_tools: true,
 710 |                         supports_streaming: true,
 711 |                         input_cost_per_million: None,
 712 |                         output_cost_per_million: None,
 713 |                     },
 714 |                 );
 715 |             }
 716 |         }
 717 | 
 718 |         let mut result: Vec<ModelInfo> = models.into_values().collect();
 719 |         result.sort_by(|a, b| a.id.cmp(&b.id));
 720 | 
 721 |         tracing::info!(
 722 |             provider = "bedrock",
 723 |             model_count = result.len(),
 724 |             "Discovered Bedrock models dynamically"
 725 |         );
 726 | 
 727 |         Ok(result)
 728 |     }
