 803 |     /// Convert our generic messages to Bedrock Converse API format.
 804 |     ///
 805 |     /// Bedrock Converse uses:
 806 |     /// - system prompt as a top-level "system" array
 807 |     /// - messages with "role" and "content" array
 808 |     /// - tool_use blocks in assistant content
 809 |     /// - toolResult blocks in user content
 810 |     ///
 811 |     /// IMPORTANT: Bedrock requires strict role alternation (user/assistant).
 812 |     /// Consecutive Role::Tool messages must be merged into a single "user"
 813 |     /// message so all toolResult blocks for a given assistant turn appear
 814 |     /// together. Consecutive same-role messages are also merged to prevent
 815 |     /// validation errors.
 816 |     fn convert_messages(messages: &[Message]) -> (Vec<Value>, Vec<Value>) {
 817 |         let mut system_parts: Vec<Value> = Vec::new();
 818 |         let mut api_messages: Vec<Value> = Vec::new();
 819 | 
 820 |         for msg in messages {
 821 |             match msg.role {
 822 |                 Role::System => {
 823 |                     let text: String = msg
 824 |                         .content
 825 |                         .iter()
 826 |                         .filter_map(|p| match p {
 827 |                             ContentPart::Text { text } => Some(text.clone()),
 828 |                             _ => None,
 829 |                         })
 830 |                         .collect::<Vec<_>>()
 831 |                         .join("\n");
 832 |                     if !text.trim().is_empty() {
 833 |                         system_parts.push(json!({"text": text}));
 834 |                     }
 835 |                 }
 836 |                 Role::User => {
 837 |                     let mut content_parts: Vec<Value> = Vec::new();
 838 |                     for part in &msg.content {
 839 |                         if let ContentPart::Text { text } = part
 840 |                             && !text.trim().is_empty()
 841 |                         {
 842 |                             content_parts.push(json!({"text": text}));
 843 |                         }
 844 |                     }
 845 |                     if !content_parts.is_empty() {
 846 |                         // Merge into previous user message if the last message is also "user"
 847 |                         if let Some(last) = api_messages.last_mut()
 848 |                             && last.get("role").and_then(|r| r.as_str()) == Some("user")
 849 |                             && let Some(arr) =
 850 |                                 last.get_mut("content").and_then(|c| c.as_array_mut())
 851 |                         {
 852 |                             arr.extend(content_parts);
 853 |                             continue;
 854 |                         }
 855 |                         api_messages.push(json!({
 856 |                             "role": "user",
 857 |                             "content": content_parts
 858 |                         }));
 859 |                     }
 860 |                 }
 861 |                 Role::Assistant => {
 862 |                     let mut content_parts: Vec<Value> = Vec::new();
 863 |                     for part in &msg.content {
 864 |                         match part {
 865 |                             ContentPart::Text { text } => {
 866 |                                 if !text.trim().is_empty() {
 867 |                                     content_parts.push(json!({"text": text}));
 868 |                                 }
 869 |                             }
 870 |                             ContentPart::ToolCall {
 871 |                                 id,
 872 |                                 name,
 873 |                                 arguments,
 874 |                                 ..
 875 |                             } => {
 876 |                                 let input: Value = serde_json::from_str(arguments)
 877 |                                     .unwrap_or_else(|_| json!({"raw": arguments}));
 878 |                                 content_parts.push(json!({
 879 |                                     "toolUse": {
 880 |                                         "toolUseId": id,
 881 |                                         "name": name,
 882 |                                         "input": input
 883 |                                     }
 884 |                                 }));
 885 |                             }
 886 |                             _ => {}
 887 |                         }
 888 |                     }
 889 |                     // Bedrock rejects whitespace-only text blocks; if the assistant message has
 890 |                     // no usable content (e.g. thinking-only), drop it from the request.
 891 |                     if content_parts.is_empty() {
 892 |                         continue;
 893 |                     }
 894 |                     // Merge into previous assistant message if consecutive
 895 |                     if let Some(last) = api_messages.last_mut()
 896 |                         && last.get("role").and_then(|r| r.as_str()) == Some("assistant")
 897 |                         && let Some(arr) = last.get_mut("content").and_then(|c| c.as_array_mut())
 898 |                     {
 899 |                         arr.extend(content_parts);
 900 |                         continue;
 901 |                     }
 902 |                     api_messages.push(json!({
 903 |                         "role": "assistant",
 904 |                         "content": content_parts
 905 |                     }));
 906 |                 }
 907 |                 Role::Tool => {
 908 |                     // Tool results must be in a "user" message with toolResult blocks.
 909 |                     // Merge into the previous user message if one exists (handles
 910 |                     // consecutive Tool messages being collapsed into one user turn).
 911 |                     let mut content_parts: Vec<Value> = Vec::new();
 912 |                     for part in &msg.content {
 913 |                         if let ContentPart::ToolResult {
 914 |                             tool_call_id,
 915 |                             content,
 916 |                         } = part
 917 |                         {
 918 |                             let content = if content.trim().is_empty() {
 919 |                                 "(empty tool result)".to_string()
 920 |                             } else {
 921 |                                 content.clone()
 922 |                             };
 923 |                             content_parts.push(json!({
 924 |                                 "toolResult": {
 925 |                                     "toolUseId": tool_call_id,
 926 |                                     "content": [{"text": content}],
 927 |                                     "status": "success"
 928 |                                 }
 929 |                             }));
 930 |                         }
 931 |                     }
 932 |                     if !content_parts.is_empty() {
 933 |                         // Merge into previous user message (from earlier Tool messages)
 934 |                         if let Some(last) = api_messages.last_mut()
 935 |                             && last.get("role").and_then(|r| r.as_str()) == Some("user")
 936 |                             && let Some(arr) =
 937 |                                 last.get_mut("content").and_then(|c| c.as_array_mut())
 938 |                         {
 939 |                             arr.extend(content_parts);
 940 |                             continue;
 941 |                         }
 942 |                         api_messages.push(json!({
 943 |                             "role": "user",
 944 |                             "content": content_parts
 945 |                         }));
 946 |                     }
 947 |                 }
 948 |             }
 949 |         }
 950 | 
 951 |         (system_parts, api_messages)
 952 |     }
 953 | 
 954 |     fn convert_tools(tools: &[ToolDefinition]) -> Vec<Value> {
 955 |         tools
 956 |             .iter()
 957 |             .map(|t| {
 958 |                 json!({
 959 |                     "toolSpec": {
 960 |                         "name": t.name,
 961 |                         "description": t.description,
 962 |                         "inputSchema": {
 963 |                             "json": t.parameters
 964 |                         }
 965 |                     }
 966 |                 })
 967 |             })
 968 |             .collect()
 969 |     }
 970 | }
