             // --- MiniMax (ON_DEMAND only, no us. prefix) ---
             "minimax-m2" => "minimax.minimax-m2",
             "minimax-m2.1" => "minimax.minimax-m2.1",

             // --- NVIDIA (ON_DEMAND only, no us. prefix) ---
             "nemotron-nano-30b" => "nvidia.nemotron-nano-3-30b",
