             "claude-opus-4" | "claude-4-opus" => "us.anthropic.claude-opus-4-20250514-v1:0",
             "claude-sonnet-4.6" | "claude-4.6-sonnet" | "claude-sonnet-4-6" => {
                 "us.anthropic.claude-sonnet-4-6-v1:0"
